def lambda_handler(event, context):
    """
    AWS Lambda handler for processing webhook events from external partners.
    Triggered by API Gateway (REST API or HTTP API).
    
    SECURITY NOTE: We use JSON (not pickle) for deserialization because
    pickle.loads() on untrusted data allows Remote Code Execution attacks.
    """
    try:
        # Extract headers (normalize to lowercase keys)
        headers = {k.lower(): v for k, v in (event.get("headers") or {}).items()}

        # Get the raw body
        body = event.get("body", "")
        if not body:
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Empty request body"}),
            }

        # Handle base64 encoded body from API Gateway
        if event.get("isBase64Encoded", False):
            import base64
            body = base64.b64decode(body).decode("utf-8")

        # Verify webhook signature before processing
        if not verify_webhook_signature(headers, body):
            logger.warning("Invalid webhook signature")
            return {
                "statusCode": 401,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Invalid signature"}),
            }

        # Safely deserialize using JSON (NEVER use pickle for external data)
        try:
            payload = json.loads(body)
        except json.JSONDecodeError as e:
            logger.error("Invalid JSON in request body: %s", str(e))
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Invalid JSON payload"}),
            }

        # Support both single events and batch events
        if isinstance(payload, list):
            events = payload
        else:
            events = [payload]

        results = []
        errors = []

        for idx, action_event in enumerate(events):
            try:
                validated = validate_event_payload(action_event)
                result = process_user_action(validated)
                results.append(result)
            except ValueError as e:
                logger.error("Validation error for event %d: %s", idx, str(e))
                errors.append({"index": idx, "error": str(e)})

        response_body = {
            "message": f"Processed {len(results)} events successfully",
            "processed": len(results),
            "errors": len(errors),
            "results": results,
        }

        if errors:
            response_body["error_details"] = errors

        status_code = 200 if not errors else (207 if results else 400)

        return {
            "statusCode": status_code,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps(response_body, default=str),
        }

    except Exception as e:
        logger.exception("Unexpected error processing webhook")
        return {
            "statusCode": 500,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": "Internal server error"}),
        }